<script setup>import{ref}from'vue';import PageActions from'../../../components/admin/PageActions.vue';import WorkSummaryCards from'../../../components/admin/WorkSummaryCards.vue';import{reportApi}from'../../../lib/reportApi.js';import{useNotifications}from'../../../composables/useNotifications.js';const notifications=useNotifications(),userId=ref(''),userIdInput=ref(null),summary=ref(null);async function search(){if(!userId.value){notifications.error('请输入采集员用户 ID');userIdInput.value?.focus();return}try{summary.value=await reportApi.collectors({userId:userId.value})}catch(e){notifications.error(e.message)}}</script>
<template><section class="admin-page"><PageActions title="采集员统计" description="按系统用户 ID 查询累计提交、当前有效、释放和废弃。"/><div class="business-card"><form class="business-inline" novalidate @submit.prevent="search"><input ref="userIdInput" v-model.trim="userId" required placeholder="采集员用户 ID"/><button class="button-primary">查询</button></form><WorkSummaryCards v-if="summary" :summary="summary.summary||summary"/></div></section></template>
